mapper.select:
SELECT mi.media_id, mi.user_id, mi.album_id, mi.title, mi.media_type, mi.uploaded_at, mi.taken_at, a.album_name, u.display_name, medium_mv.storage_key AS medium_storage_key, small_mv.storage_key AS small_storage_key, thumb_mv.storage_key AS thumb_storage_key, preview_mv.storage_key AS preview_storage_key, original_mv.storage_key AS original_storage_key, original_mv.file_org_name AS original_file_name, original_mv.mime_type AS original_mime_type, (SELECT COUNT(*) FROM MEDIA_LIKE ml WHERE ml.media_id = mi.media_id) AS like_count, (SELECT COUNT(*) FROM COMMENT c WHERE c.media_id = mi.media_id AND c.del_yn = 'N') AS comment_count, (SELECT COUNT(*) FROM MEDIA_LIKE me WHERE me.media_id = mi.media_id AND me.user_id = #{userId}) AS liked_by_me, ( SELECT GROUP_CONCAT(CONCAT(COALESCE(t.tag_scope, 'N'), '|', t.tag_name) ORDER BY CASE WHEN t.tag_scope = 'P' THEN 0 ELSE 1 END, t.tag_name SEPARATOR ',') FROM MEDIA_TAG mt JOIN TAG t ON mt.tag_id = t.tag_id WHERE mt.media_id = mi.media_id AND t.del_yn = 'N' ) AS tags_csv FROM MEDIA_ITEMS mi JOIN USER u ON mi.user_id = u.user_id JOIN ALBUM a ON mi.album_id = a.album_id LEFT JOIN MEDIA_VARIANT medium_mv ON mi.media_id = medium_mv.media_id AND medium_mv.variant_type = 'MEDIUM' LEFT JOIN MEDIA_VARIANT small_mv ON mi.media_id = small_mv.media_id AND small_mv.variant_type = 'SMALL' LEFT JOIN MEDIA_VARIANT thumb_mv ON mi.media_id = thumb_mv.media_id AND thumb_mv.variant_type = 'THUMB' LEFT JOIN MEDIA_VARIANT preview_mv ON mi.media_id = preview_mv.media_id AND preview_mv.variant_type = 'PREVIEW' LEFT JOIN MEDIA_VARIANT original_mv ON mi.media_id = original_mv.media_id AND original_mv.variant_type = 'ORIGINAL' WHERE mi.media_id IN
#{mediaId}
AND mi.del_yn = 'N' AND u.del_yn = 'N' AND a.del_yn = 'N'

mapper.delete:
DELETE FROM MEDIA_LIKE
WHERE media_id = #{mediaId}
  AND user_id = #{userId}

mapper.update:
UPDATE MEDIA_ITEMS
SET title = #{title},
    album_id = #{albumId}
WHERE media_id = #{mediaId}
  AND user_id = #{userId}
  AND del_yn = 'N'
